solution_code:
#include <iostream>
#include <iomanip>

int main()
{
    auto a { 0 };
    auto b { 0 };
    std::cin >> a >> b;

    auto intResult   { a / b };
    auto floatResult { static_cast<double>(a) / b };

    std::cout << "Int: "   << intResult << '\n';
    std::cout << std::fixed << std::setprecision(2)
              << "Float: " << floatResult << '\n';
    return 0;
}

