solution_code:
#include <iostream>

char classify(int score)
{
    if (score >= 90) return 'A';
    if (score >= 80) return 'B';
    if (score >= 70) return 'C';
    if (score >= 60) return 'D';
    return 'F';
}

int main()
{
    int score {};
    std::cin >> score;

    auto grade { classify(score) };
    std::cout << "Grade: " << grade << '\n';
    return 0;
}
